+
+pub fn getFloorDivSemantics(left: NativeType, right: NativeType) OperatorSemantics {
+    if (hasUnknownOperand(left, right)) return .runtime_dispatch;
+    if (isFloatType(left) or isFloatType(right)) return .python_floored;
+    return .zig_native;
+}

